import scala.collection.mutable

def solve(nums: Array[Long]): Long = {
    val n = nums.length
    if (n == 1) return 0L
    val MAX = 1000000
    val isPrime = Array.fill(MAX + 1)(true)
    val spf = Array.tabulate(MAX + 1)(identity)
    isPrime(0) = false
    isPrime(1) = false
    var i = 2
    while (i * i <= MAX) {
        if (isPrime(i)) {
            var j = i * i
            while (j <= MAX) {
                if (isPrime(j)) {
                    isPrime(j) = false
                    spf(j) = i
                }
                j += i
            }
        }
        i += 1
    }
    val primesInArraySet = mutable.Set[Int]()
    for (num <- nums) {
        if (num >= 2 && num <= MAX) {
            val numInt = num.toInt
            if (isPrime(numInt)) {
                primesInArraySet.add(numInt)
            }
        }
    }
    val primeToIndices = mutable.Map[Int, mutable.ListBuffer[Int]]()
    for (j <- nums.indices) {
        val num = nums(j)
        if (num >= 2 && num <= MAX) {
            var x = num.toInt
            val factors = mutable.Set[Int]()
            var temp = x
            while (temp > 1) {
                val p = spf(temp)
                factors.add(p)
                while (temp % p == 0) {
                    temp /= p
                }
            }
            for (p <- factors) {
                if (primesInArraySet.contains(p)) {
                    if (!primeToIndices.contains(p)) {
                        primeToIndices(p) = mutable.ListBuffer[Int]()
                    }
                    primeToIndices(p) += j
                }
            }
        }
    }
    val visited = Array.fill(n)(false)
    val usedPrimes = mutable.Set[Int]()
    val queue = mutable.Queue[Int]()
    queue.enqueue(0)
    visited(0) = true
    var steps = 0
    while (queue.nonEmpty) {
        val nextQueue = mutable.Queue[Int]()
        for (cur <- queue) {
            for (d <- List(-1, 1)) {
                val neighbor = cur + d
                if (neighbor >= 0 && neighbor < n) {
                    if (neighbor == n - 1) {
                        return steps + 1
                    }
                    if (!visited(neighbor)) {
                        visited(neighbor) = true
                        nextQueue.enqueue(neighbor)
                    }
                }
            }
            val num = nums(cur)
            if (num >= 2 && num <= MAX) {
                val p = num.toInt
                if (isPrime(p) && !usedPrimes.contains(p)) {
                    usedPrimes.add(p)
                    primeToIndices.get(p).foreach { indices =>
                        for (j <- indices) {
                            if (j == n - 1) {
                                return steps + 1
                            }
                            if (j != cur && !visited(j)) {
                                visited(j) = true
                                nextQueue.enqueue(j)
                            }
                        }
                    }
                }
            }
        }
        steps += 1
        queue.clear()
        queue.enqueueAll(nextQueue)
    }
    -1
}
