import scala.collection.mutable

def solve(nums: Array[Long]): Long = {
    val n = nums.length
    if (n == 0) return 0L
    val max_val = 1000000
    val spf = (0 to max_val).toArray
    val isPrime = Array.fill(max_val + 1)(false)
    if (max_val >= 2) {
        for (i <- 2 to max_val) {
            if (spf(i) == i) {
                isPrime(i) = true
                var j = i * 2
                while (j <= max_val) {
                    if (spf(j) == j) {
                        spf(j) = i
                    }
                    j += i
                }
            }
        }
    }

    val indexGroups = Array.fill(max_val + 1)(mutable.ListBuffer[Int]())
    for (j <- nums.indices) {
        val x = nums(j).toInt
        if (x > 1 && x <= max_val) {
            var temp = x
            var last = -1
            while (temp > 1) {
                val p = spf(temp)
                if (p != last) {
                    if (p <= max_val) {
                        indexGroups(p) += j
                    }
                    last = p
                }
                while (temp % p == 0) {
                    temp /= p
                }
            }
        }
    }

    val dist = Array.fill(n)(-1)
    val groupDone = Array.fill(max_val + 1)(false)
    val queue = mutable.Queue[Int]()
    dist(0) = 0
    queue.enqueue(0)

    while (queue.nonEmpty) {
        val i = queue.dequeue()
        if (i == n - 1) {
            return dist(i).toLong
        }

        if (i - 1 >= 0 && dist(i - 1) == -1) {
            dist(i - 1) = dist(i) + 1
            queue.enqueue(i - 1)
        }
        if (i + 1 < n && dist(i + 1) == -1) {
            dist(i + 1) = dist(i) + 1
            queue.enqueue(i + 1)
        }

        val num_i = nums(i).toInt
        if (num_i >= 2 && num_i <= max_val && isPrime(num_i) && !groupDone(num_i)) {
            groupDone(num_i) = true
            for (j <- indexGroups(num_i)) {
                if (j != i && dist(j) == -1) {
                    dist(j) = dist(i) + 1
                    queue.enqueue(j)
                }
            }
        }
    }

    dist(n - 1).toLong
}
