import scala.collection.mutable

def solve(nums: Array[Long]): Long = {
    val n = nums.length
    if (n == 1) return 0L

    val MAX = 1000000
    val spf = Array.tabulate(MAX + 1)(i => i)

    for (i <- 2 to math.sqrt(MAX).toInt) {
        if (spf(i) == i) {
            var j = i * i
            while (j <= MAX) {
                if (spf(j) == j)
                    spf(j) = i
                j += i
            }
        }
    }

    val isPrimeArray = Array.ofDim[Boolean](MAX + 1)
    for (i <- 2 to MAX) {
        isPrimeArray(i) = (spf(i) == i)
    }

    val factorMap = mutable.Map.empty[Int, mutable.ArrayBuffer[Int]]

    for (idx <- nums.indices) {
        val numVal = nums(idx).toInt
        if (numVal != 1) {
            var temp = numVal
            val primeFactors = mutable.Set.empty[Int]
            while (temp > 1) {
                val p = spf(temp)
                primeFactors.add(p)
                while (spf(temp) == p) {
                    temp /= p
                }
            }
            for (p <- primeFactors) {
                factorMap.getOrElseUpdate(p, mutable.ArrayBuffer.empty[Int]) += idx
            }
        }
    }

    val dist = Array.fill(n)(-1)
    val queue = mutable.Queue[Int]()
    dist(0) = 0
    queue.enqueue(0)

    val processedPrimes = mutable.Set[Int]()

    while (queue.nonEmpty) {
        val i = queue.dequeue()
        val steps = dist(i)

        if (i == n - 1) {
            return steps.toLong
        }

        val neighbors = List(i - 1, i + 1)
        for (neighbor <- neighbors) {
            if (neighbor >= 0 && neighbor < n && dist(neighbor) == -1) {
                dist(neighbor) = steps + 1
                queue.enqueue(neighbor)
            }
        }

        val currentValue = nums(i).toInt
        if (currentValue >= 2 && isPrimeArray(currentValue)) {
            if (!processedPrimes.contains(currentValue)) {
                processedPrimes.add(currentValue)
                factorMap.get(currentValue).foreach { indices =>
                    for (j <- indices) {
                        if (j != i && dist(j) == -1) {
                            dist(j) = steps + 1
                            queue.enqueue(j)
                        }
                    }
                }
            }
        }
    }

    dist(n - 1).toLong
}
