import scala.collection.mutable

def solve(nums: Array[Long]): Long = {
  val n = nums.length
  if (n == 1) return 0

  val MAX_VAL = 1000000
  val isPrimeArr = Array.fill(MAX_VAL + 1)(true)
  isPrimeArr(0) = false
  isPrimeArr(1) = false
  val spfArr = (0 to MAX_VAL).toArray
  var i = 2
  while (i * i <= MAX_VAL) {
    if (isPrimeArr(i)) {
      var j = i * i
      while (j <= MAX_VAL) {
        isPrimeArr(j) = false
        if (spfArr(j) == j) {
          spfArr(j) = i
        }
        j += i
      }
    }
    i += 1
  }

  val primesInArray = mutable.Set[Long]()
  val primeToIndices = mutable.Map[Long, mutable.ArrayBuffer[Int]]()

  for (i <- 0 until n) {
    val num = nums(i)
    if (num >= 2 && num <= MAX_VAL) {
      val numInt = num.toInt
      if (isPrimeArr(numInt)) {
        primesInArray += num
      }
    }
  }

  for (j <- 0 until n) {
    val num = nums(j).toInt
    if (num > 1) {
      var temp = num
      val factors = mutable.Set[Int]()
      while (temp > 1) {
        val p = spfArr(temp)
        factors.add(p)
        while (temp % p == 0) {
          temp /= p
        }
      }
      for (p <- factors) {
        val pLong = p.toLong
        if (primesInArray.contains(pLong)) {
          val indices = primeToIndices.getOrElseUpdate(pLong, mutable.ArrayBuffer[Int]())
          indices += j
        }
      }
    }
  }

  val K = primesInArray.size
  val primeToVirtualId = mutable.Map[Long, Int]()
  val virtualNodeToPrime = mutable.Map[Int, Long]()
  var nextId = n
  for (p <- primesInArray) {
    primeToVirtualId(p) = nextId
    virtualNodeToPrime(nextId) = p
    nextId += 1
  }

  val totalNodes = n + K
  val dist = Array.fill(totalNodes)(-1)
  val q = mutable.ArrayDeque[Int]()
  dist(0) = 0
  q.append(0)

  while (q.nonEmpty) {
    val u = q.removeHead()
    if (u == n - 1) {
      return dist(u)
    }

    if (u < n) {
      for (v <- List(u - 1, u + 1)) {
        if (v >= 0 && v < n && dist(v) == -1) {
          dist(v) = dist(u) + 1
          q.append(v)
        }
      }

      val numVal = nums(u)
      if (numVal >= 2 && numVal <= MAX_VAL) {
        val numInt = numVal.toInt
        if (isPrimeArr(numInt) && primesInArray.contains(numVal)) {
          primeToVirtualId.get(numVal) match {
            case Some(vp) =>
              if (dist(vp) == -1) {
                dist(vp) = dist(u) + 1
                q.append(vp)
              }
            case None => 
          }
        }
      }
    } else {
      virtualNodeToPrime.get(u) match {
        case Some(p) =>
          primeToIndices.get(p) match {
            case Some(indices) =>
              for (j <- indices) {
                if (j < n && dist(j) == -1) {
                  dist(j) = dist(u)
                  q.prepend(j)
                }
              }
            case None => 
          }
        case None => 
      }
    }
  }

  dist(n - 1)
}
